// Server-side idempotency middleware (simplified)
async function withIdempotency(req, res, handler) {
  const key = req.header('Idempotency-Key');
  if (!key) return res.status(400).json(problem('idempotency-key-required'));

  // Atomically claim the key. INSERT ... ON CONFLICT DO NOTHING returns
  // the row only when we won the race; otherwise someone else owns it.
  const claimed = await db.claimKey(key, req.userId, hashBody(req.body));
  if (!claimed) {
    const existing = await db.getKey(key);
    if (existing.requestHash !== hashBody(req.body))
      return res.status(422).json(problem('idempotency-key-reuse-mismatch'));
    if (existing.status === 'in_progress')
      return res.status(409).json(problem('idempotent-request-in-flight'));
    return res.status(existing.httpStatus).json(existing.responseBody); // replay
  }

  const result = await handler(req); // do the real work exactly once
  await db.finalizeKey(key, result.status, result.body);
  return res.status(result.status).json(result.body);
}

// Client: generate the key ONCE per logical payment attempt, reuse on retry.
const idempotencyKey = uuidv4(); // created before the first try, not per retry
async function charge(payload) {
  return httpPostWithRetry('/v1/payments', payload, {
    headers: { 'Idempotency-Key': idempotencyKey },
    retry: { attempts: 3, on: ['timeout', 502, 503, 504] }
  });
}
// Server stores (key -> first result). The retried POST replays the stored
// 201 and the SAME payment id, so the PSP is never charged twice.

