import { createHash } from 'crypto';

type KeyRow = {
  key: string; userId: string; requestHash: string;
  status: 'in_progress' | 'completed';
  httpStatus?: number; responseBody?: unknown; paymentId?: string;
};

function problem(type: string, title: string, status: number, detail?: string) {
  return { type: `https://api.acme.com/problems/${type}`, title, status, detail };
}
const hashBody = (b: unknown) => createHash('sha256').update(JSON.stringify(b)).digest('hex');

export async function createPayment(req, res, db, psp) {
  const key = req.header('Idempotency-Key');
  if (!key) {
    return res.status(400).type('application/problem+json')
      .json(problem('idempotency-key-required', 'Idempotency-Key header is required', 400));
  }
  const bodyHash = hashBody(req.body);

  // (1) Atomic claim. Returns the new row only if WE won the insert race.
  const claimed: KeyRow | null = await db.query(
    `INSERT INTO idempotency_keys (key, user_id, request_hash, status)
     VALUES ($1, $2, $3, 'in_progress')
     ON CONFLICT (key) DO NOTHING
     RETURNING *`, [key, req.userId, bodyHash]
  ).then(r => r.rows[0] ?? null);

  if (!claimed) {
    // Key already exists: someone else owns it. Inspect and replay/reject.
    const existing: KeyRow = (await db.query(
      `SELECT * FROM idempotency_keys WHERE key = $1`, [key])).rows[0];
    if (existing.request_hash !== bodyHash) {
      return res.status(422).type('application/problem+json').json(
        problem('idempotency-key-reuse', 'Key reused with a different request body', 422));
    }
    if (existing.status === 'in_progress') {
      return res.status(409).type('application/problem+json').json(
        problem('request-in-flight', 'A request with this key is still processing', 409));
    }
    return res.status(existing.http_status).json(existing.response_body); // (3) replay
  }

  // (2) We won the claim -> do the real charge EXACTLY once.
  try {
    const payment = await psp.charge({
      amountCents: req.body.amountCents, currency: req.body.currency,
      source: req.body.source, idempotencyKey: key, // pass through to PSP too
    });
    const body = { id: payment.id, status: payment.status,
                   amountCents: payment.amountCents, currency: payment.currency };
    await db.query(
      `UPDATE idempotency_keys
         SET status='completed', http_status=201, response_body=$2, payment_id=$3
       WHERE key=$1`, [key, body, payment.id]);
    return res.status(201).location(`/v1/payments/${payment.id}`).json(body);
  } catch (err) {
    // Release the claim so a legitimate retry can try again.
    await db.query(`DELETE FROM idempotency_keys WHERE key=$1 AND status='in_progress'`, [key]);
    return res.status(502).type('application/problem+json').json(
      problem('payment-provider-error', 'Upstream payment provider failed', 502, String(err)));
  }
}

type Cursor = { ts: string; id: string };

const encodeCursor = (c: Cursor): string =>
  Buffer.from(JSON.stringify(c)).toString('base64url');

function decodeCursor(raw?: string): Cursor | null {
  if (!raw) return null;
  try {
    const c = JSON.parse(Buffer.from(raw, 'base64url').toString('utf8'));
    if (typeof c.ts === 'string' && typeof c.id === 'string') return c;
    return null;
  } catch { return null; }
}

export async function listPayments(req, res, db) {
  const limit = Math.min(Math.max(parseInt(req.query.limit ?? '20', 10), 1), 100);
  const cursor = decodeCursor(req.query.cursor);
  if (req.query.cursor && !cursor) {
    return res.status(400).type('application/problem+json').json({
      type: 'https://api.acme.com/problems/invalid-cursor',
      title: 'Invalid cursor', status: 400,
    });
  }

  // Fetch limit + 1 to detect whether another page exists.
  const params: any[] = [req.tenantId];
  let where = 'tenant_id = $1';
  if (cursor) {
    // Tuple comparison gives a clean, index-friendly keyset predicate.
    where += ' AND (created_at, id) < ($2, $3)';
    params.push(cursor.ts, cursor.id);
  }
  const rows = (await db.query(
    `SELECT id, created_at, amount_cents, currency, status
       FROM payments
      WHERE ${where}
      ORDER BY created_at DESC, id DESC
      LIMIT ${limit + 1}`, params)).rows;

  const hasMore = rows.length > limit;
  const items = hasMore ? rows.slice(0, limit) : rows;
  const last = items[items.length - 1];
  const nextCursor = hasMore && last
    ? encodeCursor({ ts: last.created_at.toISOString(), id: last.id })
    : null;

  return res.status(200)
    .set('Cache-Control', 'private, max-age=0, must-revalidate')
    .json({ items, nextCursor });
}

